const raw = $json.text || $json.output || $json;

let paper;

try {
  paper = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error("Invalid JSON from LLM.");
}

// =========================
// SLACK FORMAT
// =========================

let slackMessage = `*${paper.masthead || "Daily News"}*\n`;
slackMessage += `_${paper.date || ""}_\n\n`;

slackMessage += `*${paper.lead_story.headline}*\n`;
slackMessage += `_${paper.lead_story.subheadline}_\n\n`;
slackMessage += `${paper.lead_story.byline}\n`;
slackMessage += `${paper.lead_story.dateline}\n\n`;
slackMessage += `${paper.lead_story.content}\n\n`;

if (paper.lead_story.image_url) {
  slackMessage += `${paper.lead_story.image_url}\n`;
  slackMessage += `_${paper.lead_story.image_caption}_\n\n`;
}

paper.secondary_stories.forEach(story => {
  slackMessage += `*${story.headline}*\n`;
  slackMessage += `${story.content}\n`;
  if (story.image_url) {
    slackMessage += `${story.image_url}\n`;
    slackMessage += `_${story.image_caption}_\n`;
  }
  slackMessage += "\n";
});

slackMessage += `_${paper.editorial_note}_`;


// =========================
// HTML NEWSPAPER FORMAT
// =========================

let html = `
<div style="font-family: Georgia, serif; max-width: 900px; margin: auto; background:#ffffff; padding:20px; border:1px solid #ddd;">

  <div style="text-align:center; border-bottom:3px solid black; padding-bottom:10px;">
    <h1 style="font-size:48px; margin:0;">${paper.masthead}</h1>
    <p style="margin:5px 0; font-size:14px;">${paper.date}</p>
  </div>

  <div style="margin-top:30px;">
    <h2 style="font-size:32px; margin-bottom:5px;">${paper.lead_story.headline}</h2>
    <h3 style="font-weight:normal; color:gray;">${paper.lead_story.subheadline}</h3>
    <p style="font-size:14px;"><b>${paper.lead_story.byline}</b> | ${paper.lead_story.dateline}</p>
  </div>
`;

if (paper.lead_story.image_url) {
  html += `
    <img src="${paper.lead_story.image_url}" style="width:100%; margin-top:15px;" />
    <p style="font-size:12px; color:gray;"><i>${paper.lead_story.image_caption}</i></p>
  `;
}

html += `
  <div style="column-count:2; column-gap:30px; margin-top:20px; font-size:16px; line-height:1.6;">
    ${paper.lead_story.content.replace(/\n/g, "<br><br>")}
  </div>

  <hr style="margin:40px 0; border:1px solid #ccc;"/>
`;

paper.secondary_stories.forEach(story => {
  html += `
    <h3 style="font-size:22px;">${story.headline}</h3>
  `;

  if (story.image_url) {
    html += `
      <img src="${story.image_url}" style="width:100%; margin-top:10px;" />
      <p style="font-size:12px; color:gray;"><i>${story.image_caption}</i></p>
    `;
  }

  html += `
    <div style="font-size:15px; line-height:1.6;">
      ${story.content.replace(/\n/g, "<br><br>")}
    </div>
    <hr style="margin:30px 0; border:1px solid #eee;"/>
  `;
});

html += `
  <div style="text-align:center; font-style:italic; margin-top:40px; font-size:14px;">
    ${paper.editorial_note}
  </div>
</div>
`;

return [{
  json: {
    slackMessage,
    html,
    subject: paper.lead_story.headline || "Daily Newspaper"
  }
}];
